import api from "./app/client";

export interface LogEntry {
  id?: string;
  timestamp: string;
  level: string;
  message: string;
  exception?: string;
  sourceContext?: string;
  [key: string]: any;
}

export interface GetLogsParams {
  search?: string;
  level?: string;
  page?: number;
  pageSize?: number;
}

export interface PaginatedLogs {
  items: LogEntry[];
  totalCount: number;
}

export const logService = {
  getLogs: async (params?: GetLogsParams): Promise<PaginatedLogs> => {
    try {
      // Backend exposes logs at /api/admin/logs (api client base already includes /api)
      const response = await api.get('/admin/logs', { params });
      
      // Handle various response types (paged vs unpaged array)
      if (Array.isArray(response.data)) {
        return { items: response.data, totalCount: response.data.length };
      }
      return response.data;
    } catch (error) {
      console.error("Error fetching logs:", error);
      throw error;
    }
  },
};
