import { useState } from "react";
import { useQuery } from "@tanstack/react-query";
import {
  Search,
  RefreshCw,
  AlertTriangle,
  Info,
  AlertCircle,
  ChevronDown,
  ChevronUp,
  Activity,
} from "lucide-react";
import { logService } from "@/api/logService";
import type { LogEntry } from "@/api/logService";
import { Switch } from "@/shadcn/components/ui/switch";

const getLevelIcon = (level: string) => {
  const l = (level || "").toLowerCase();
  if (l === "error" || l === "fatal") return <AlertCircle className="w-3.5 h-3.5 text-red-500 dark:text-red-400" />;
  if (l === "warning" || l === "warn") return <AlertTriangle className="w-3.5 h-3.5 text-amber-500 dark:text-amber-400" />;
  return <Info className="w-3.5 h-3.5 text-primary" />;
};

const getLevelBadgeClass = (level: string) => {
  const l = (level || "").toLowerCase();
  if (l === "error" || l === "fatal") return "bg-red-50 text-red-700 border-red-200 dark:bg-red-950/60 dark:text-red-300 dark:border-red-800";
  if (l === "warning" || l === "warn") return "bg-amber-50 text-amber-700 border-amber-200 dark:bg-amber-950/60 dark:text-amber-300 dark:border-amber-800";
  return "bg-primary/10 text-primary border-primary/20";
};

const getRowAccentClass = (level: string) => {
  const l = (level || "").toLowerCase();
  if (l === "error" || l === "fatal") return "border-l-2 border-l-red-400";
  if (l === "warning" || l === "warn") return "border-l-2 border-l-amber-400";
  return "border-l-2 border-l-transparent";
};

const LogRow = ({ log }: { log: LogEntry }) => {
  const [expanded, setExpanded] = useState(false);
  const dateStr = log.timestamp ? new Date(log.timestamp).toLocaleString() : "Unknown";

  return (
    <>
      <tr
        className={`border-b border-border cursor-pointer transition-colors group ${getRowAccentClass(log.level)} ${expanded ? "bg-muted/30" : "hover:bg-muted/20"}`}
        onClick={() => setExpanded(!expanded)}
      >
        <td className="px-5 py-3.5 whitespace-nowrap hidden sm:table-cell">
          <span className="text-xs font-medium text-muted-foreground tabular-nums">{dateStr}</span>
        </td>

        <td className="px-5 py-3.5">
          <span className={`inline-flex items-center gap-1.5 px-2.5 py-1 rounded-lg text-[11px] font-bold border tracking-wide ${getLevelBadgeClass(log.level)}`}>
            {getLevelIcon(log.level)}
            {(log.level || "INFO").toUpperCase()}
          </span>
        </td>

        <td className="px-5 py-3.5">
          <div className="text-sm font-medium text-foreground/70 line-clamp-1 group-hover:text-foreground transition-colors">
            {log.message || "No message content."}
          </div>
        </td>

        <td className="px-5 py-3.5 text-right w-12">
          <button
            className="w-7 h-7 inline-flex items-center justify-center rounded-lg text-muted-foreground/40 hover:text-foreground hover:bg-muted transition-all"
            onClick={(e) => { e.stopPropagation(); setExpanded(!expanded); }}
          >
            {expanded ? <ChevronUp className="w-3.5 h-3.5" /> : <ChevronDown className="w-3.5 h-3.5" />}
          </button>
        </td>
      </tr>

      {expanded && (
        <tr>
          <td colSpan={4} className="p-0 border-b border-border">
            <div className="px-7 py-5 bg-muted/30 space-y-4">

              <div>
                <p className="text-[10px] font-bold text-muted-foreground uppercase tracking-widest mb-2">Full Message</p>
                <div className="p-3.5 bg-card rounded-xl border border-border shadow-sm text-sm text-foreground font-mono overflow-auto max-h-36 leading-relaxed">
                  {log.message || "None"}
                </div>
              </div>

              {log.exception && (
                <div>
                  <p className="text-[10px] font-bold text-red-500 dark:text-red-400 uppercase tracking-widest mb-2">Exception</p>
                  <div className="p-3.5 bg-red-50/80 dark:bg-red-950/30 rounded-xl border border-red-100 dark:border-red-900 text-sm text-red-800 dark:text-red-300 font-mono whitespace-pre-wrap overflow-auto max-h-48 leading-relaxed shadow-sm">
                    {log.exception}
                  </div>
                </div>
              )}

              {log.properties && Object.keys(log.properties).length > 0 && (
                <div>
                  <p className="text-[10px] font-bold text-muted-foreground uppercase tracking-widest mb-2">Properties</p>
                  <div className="p-3.5 bg-card rounded-xl border border-border shadow-sm overflow-auto max-h-36">
                    <pre className="text-xs text-foreground/80 font-mono leading-relaxed">
                      {JSON.stringify(log.properties, null, 2)}
                    </pre>
                  </div>
                </div>
              )}

            </div>
          </td>
        </tr>
      )}
    </>
  );
};

export default function Logs() {
  const [searchTerm, setSearchTerm] = useState("");
  const [levelFilter, setLevelFilter] = useState("All");
  const [isAutoRefresh, setIsAutoRefresh] = useState(false);

  const { data, isLoading, refetch, isRefetching, isError, error } = useQuery({
    queryKey: ["backend-logs", searchTerm, levelFilter],
    queryFn: () =>
      logService.getLogs({
        search: searchTerm || undefined,
        level: levelFilter !== "All" ? levelFilter : undefined,
      }),
    refetchInterval: isAutoRefresh ? 10000 : false,
  });

  const logs = data?.items || [];

  return (
    <div className="page-wrapper space-y-5">

      <div className="section-card overflow-hidden">
        <div className="px-8 pt-7 pb-6 flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
          <div className="flex items-center gap-4">
            <div className="w-11 h-11 rounded-xl bg-primary/10 border border-primary/20 flex items-center justify-center shadow-sm shrink-0">
              <Activity className="w-5 h-5 text-primary" />
            </div>
            <div>
              <h1 className="page-title text-foreground font-bold tracking-tight">System Logs</h1>
              <p className="page-subtitle text-muted-foreground text-sm font-medium mt-0.5">
                Real-time monitoring and historical backend activity.
              </p>
            </div>
          </div>

          {isAutoRefresh && (
            <div className="inline-flex items-center gap-2 px-3 py-1.5 bg-emerald-50 dark:bg-emerald-950/40 border border-emerald-200/80 dark:border-emerald-800 rounded-xl self-start sm:self-auto">
              <span className="w-2 h-2 rounded-full bg-emerald-400 animate-pulse" />
              <span className="text-[11px] font-bold text-emerald-700 dark:text-emerald-400 uppercase tracking-wider">Live</span>
            </div>
          )}
        </div>

        <div className="flex flex-col sm:flex-row gap-3 items-stretch sm:items-center px-6 pb-5 border-t border-border pt-4">

          <div className="relative flex-1">
            <Search className="absolute left-3.5 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground pointer-events-none" />
            <input
              type="text"
              className="w-full pl-10 pr-4 py-2.5 bg-muted/50 border border-border rounded-xl text-sm text-foreground placeholder:text-muted-foreground font-medium focus:outline-none focus:ring-2 focus:ring-primary/30 focus:border-primary focus:bg-background transition-all"
              placeholder="Search logs by message…"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>

          <div className="relative w-full sm:w-44">
            <select
              className="w-full appearance-none pl-3.5 pr-9 py-2.5 bg-muted/50 border border-border rounded-xl text-sm text-foreground font-medium focus:outline-none focus:ring-2 focus:ring-primary/30 focus:border-primary focus:bg-background transition-all cursor-pointer"
              value={levelFilter}
              onChange={(e) => setLevelFilter(e.target.value)}
            >
              <option value="All">All Levels</option>
              <option value="Information">Info</option>
              <option value="Warning">Warning</option>
              <option value="Error">Error</option>
              <option value="Debug">Debug</option>
            </select>
            <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground pointer-events-none" />
          </div>

          <div className="hidden sm:block w-px h-7 bg-border self-center" />

          <div className="flex items-center gap-2.5 shrink-0 self-center">
            <span className="text-sm text-foreground font-semibold whitespace-nowrap">Auto Refresh</span>
            <Switch checked={isAutoRefresh} onCheckedChange={setIsAutoRefresh} />
          </div>

          <button
            onClick={() => refetch()}
            disabled={isLoading || isRefetching}
            title="Refresh"
            className="inline-flex items-center justify-center w-10 h-10 rounded-xl border border-border bg-card text-muted-foreground hover:bg-muted hover:border-border/80 hover:text-foreground transition-all disabled:opacity-50 shadow-sm shrink-0 self-center"
          >
            <RefreshCw className={`w-4 h-4 ${isRefetching ? "animate-spin text-primary" : ""}`} />
          </button>
        </div>
      </div>

      {isError && (
        <div className="flex items-start gap-3 p-4 bg-destructive/10 border border-destructive/20 rounded-2xl shadow-sm">
          <div className="w-7 h-7 bg-destructive/20 rounded-lg flex items-center justify-center shrink-0 mt-0.5">
            <AlertCircle className="w-3.5 h-3.5 text-destructive" />
          </div>
          <div>
            <p className="text-sm font-bold text-destructive">Failed to fetch logs</p>
            <p className="text-sm font-medium text-destructive/80 mt-0.5">
              {(error as Error)?.message ?? "Check API route and permissions."}
            </p>
          </div>
        </div>
      )}

      <div className="section-card overflow-hidden !mb-0">
        <table className="w-full">
          <thead>
            <tr className="bg-muted/30 border-b border-border">
              <th className="hidden sm:table-cell px-5 py-3.5 text-left w-52">
                <span className="text-[10px] font-bold text-muted-foreground uppercase tracking-widest">Timestamp</span>
              </th>
              <th className="px-5 py-3.5 text-left w-36">
                <span className="text-[10px] font-bold text-muted-foreground uppercase tracking-widest">Level</span>
              </th>
              <th className="px-5 py-3.5 text-left">
                <span className="text-[10px] font-bold text-muted-foreground uppercase tracking-widest">Message</span>
              </th>
              <th className="w-12" />
            </tr>
          </thead>
          <tbody>
            {isLoading && (
              <tr>
                <td colSpan={4} className="py-20 text-center">
                  <div className="flex flex-col items-center gap-3">
                    <div className="w-10 h-10 rounded-xl bg-primary/10 flex items-center justify-center">
                      <RefreshCw className="w-5 h-5 animate-spin text-primary" />
                    </div>
                    <div>
                      <p className="text-sm font-semibold text-foreground">Loading logs</p>
                      <p className="text-xs text-muted-foreground mt-0.5 font-medium">Fetching system activity…</p>
                    </div>
                  </div>
                </td>
              </tr>
            )}

            {!isLoading && logs.length === 0 && (
              <tr>
                <td colSpan={4} className="py-24 text-center">
                  <div className="flex flex-col items-center gap-3">
                    <div className="w-12 h-12 rounded-2xl bg-muted flex items-center justify-center">
                      <Search className="w-5 h-5 text-muted-foreground" />
                    </div>
                    <div>
                      <p className="text-sm font-semibold text-foreground">No logs found</p>
                      <p className="text-xs text-muted-foreground mt-1 font-medium">Try adjusting your filters or search term</p>
                    </div>
                  </div>
                </td>
              </tr>
            )}

            {!isLoading && logs.map((log, index) => (
              <LogRow key={log.id || index} log={log} />
            ))}
          </tbody>
        </table>

        {!isLoading && logs.length > 0 && (
          <div className="px-5 py-3 border-t border-border bg-muted/20 flex items-center justify-between">
            <p className="text-xs font-semibold text-muted-foreground">
              Showing <span className="text-foreground">{logs.length}</span> {logs.length === 1 ? "entry" : "entries"}
            </p>
            {isAutoRefresh && (
              <p className="text-xs font-medium text-muted-foreground flex items-center gap-1.5">
                <span className="w-1.5 h-1.5 rounded-full bg-emerald-400 animate-pulse inline-block" />
                Refreshes every 10s
              </p>
            )}
          </div>
        )}
      </div>

    </div>
  );
}
